    30→function useCountUp(end: number, duration: number = 2000) {
    31→  const [count, setCount] = useState(0);
    32→  const [hasAnimated, setHasAnimated] = useState(false);
    33→  const ref = useRef<HTMLSpanElement>(null);
    34→
    35→  useEffect(() => {
    36→    const observer = new IntersectionObserver((entries) => {
    37→      if (entries[0].isIntersecting && !hasAnimated) {
    38→        setHasAnimated(true);
    39→        let startTimestamp: number | null = null;
    40→        const step = (timestamp: number) => {
    41→          if (!startTimestamp) startTimestamp = timestamp;
    42→          const progress = Math.min((timestamp - startTimestamp) / duration, 1);
    43→          setCount(Math.floor(progress * end));
    44→          if (progress < 1) {
    45→            window.requestAnimationFrame(step);
    46→          }
    47→        };
    48→        window.requestAnimationFrame(step);
    49→      }
    50→    }, { threshold: 0.1 });
    51→
    52→    if (ref.current) observer.observe(ref.current);
    53→    return () => observer.disconnect();
    54→  }, [end, duration, hasAnimated]);
    55→
    56→  return { count, ref };
    57→}
